var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"바다에서 몰려오는 놈들은 처리했어.","JPN":"海から押し寄せてくるやつらは片付けたぞ。","ENG":"Handled the ones coming in from the sea.","TWN":"從海上靠近的都解決了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 이제 됐지?","JPN":"おい、これでいいだろ？","ENG":"Hey, we're done here, right?","TWN":"喂，這樣可以了吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 사람들 대피시키든 말든 결정하는 건 네가 해.","JPN":"ここの人たちを避難させるかどうかはお前が決めろ。","ENG":"Whether you evacuate these people or not, that's your call.","TWN":"妳自己決定這些人要不要撤走。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 많은 침식체들을…….","JPN":"あんなに多かった侵食体を……","ENG":"All those C.O.s...","TWN":"那麼多侵蝕體……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저 정도 되는 카운터를 정보부인 내가 몰랐다고?","JPN":"あれほどのカウンターを、情報部の私が知らなかったなんてあり得る？","ENG":"And I, an intelligence agent, didn't know a Counter like that existed?","TWN":"在情報部的我居然不知道有這種制裁者？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"프론트 베이… 도대체 무슨 괴물을 숨겨둔 거야?","JPN":"フロントベイ……なんて化け物を隠していたの？","ENG":"Front Bay... just what kind of monster were you hiding?","TWN":"前灣……究竟藏了什麼怪物啊？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네네 고향을 지켜줘서 감사함다!","JPN":"モネの故郷を守ってくれてありがとうっす！","ENG":"Thank you for protecting Mone's hometown!","TWN":"謝謝你們守住莫妮的故鄉！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람을 막지 못하면 이곳도 언젠간 물에 잠기거나 침식체 밭이 될 거야.","JPN":"黒い氾濫を食い止められなかったら、ここもいつかは水に沈むか侵食体の巣窟になる。","ENG":"If we don't stop the Black Flood, this place will end up underwater, or overrun with C.O.s, eventually.","TWN":"如果無法阻止黑色洪災，這裡遲早也會被淹沒或變成侵蝕體巢穴。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금이라도 사람들을 모아서 떠나라고 해.","JPN":"すぐにでもみんなを集めて、ここから離れたほうが身のためだな。","ENG":"Tell everyone to gather their things and leave while they can.","TWN":"現在帶著大家離開吧。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기도 리코리스 같은 분이 계셨군요.","JPN":"こちらにもリコリスのようなお方が。","ENG":"So there's someone like Lycoris here too.","TWN":"原來這裡也有像莉克麗絲這樣的人啊。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저희는 이곳을 지키기 위해 남은 겁니다.","JPN":"私たちはここを守るために残ったのです。","ENG":"We stayed because we want to protect this island.","TWN":"我們留下是為了保護這座島。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"많은 사람들의 추억이 서린 이 섬을요.","JPN":"多くの人の思い出が詰まったこの島を。","ENG":"An island full of people's memories.","TWN":"這裡承載著許多人的回憶。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네는 이 섬 안 떠날 검다!","JPN":"モネは島から出ないっす！","ENG":"Mone will not leave this island!","TWN":"莫妮不會離開這座島！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"부모님도, 다른 사람들도 마찬가지임다!","JPN":"両親も、他の人たちも同じっす！","ENG":"My parents won't, and neither will anyone else!","TWN":"我的父母和其他人都一樣！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 지금이 무슨 소꿉장난 하러 온 줄 알아?!","JPN":"くそ、おままごとしに来たんじゃないんだぞ！","ENG":"Damn it. What do you think this is, playtime?!","TWN":"可惡，你們以為現在在玩扮家家酒嗎？！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통. 이런 건 관리국에서 강제로 데려가고 그런 거 없어?","JPN":"おい、ポンコツ。こういうの管理局で強制的に連れて行ったりとかできないのか？","ENG":"Hey, tin can. Doesn't the Administration ever just haul people out by force?","TWN":"喂，鐵桶，這種時候管理局不能強制撤離嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"권고는 할 수 있지만, 응하는 건 개인의 선택이에요.","JPN":"勧告はできますが、それに応じるのは個人の選択です。","ENG":"We can recommend evacuation, but whether they accept is their choice.","TWN":"可以勸告，但是否接受是個人選擇。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"게다가 이토록 확고한 분들이라면…….","JPN":"それに、これほどに意志の固い方々なら……","ENG":"And if their resolve is this firm, then...","TWN":"而且看他們這麼堅定，應該勸不了……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"자, 잠깐만요.","JPN":"ま、待ってください。","ENG":"W-wait.","TWN":"等、等一下。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"근방에서 차원 계면 손상이 감지되고 있어요!","JPN":"近くで次元界面の損傷が感知されています！","ENG":"Dimension surface damage detected nearby!","TWN":"附近偵測到次元界面受損！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"차, 차원 계면을 찢고 침식체가……?","JPN":"じ、次元界面を破って侵食体が……？","ENG":"Th-the C.O. is tearing through the dimension surface?!","TWN":"侵、侵蝕體破壞次元界面……？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"위험해요! 여러분들은 서둘러 섬주민들을 피신시켜주세요!","JPN":"危険です！　皆さんは急いで島の住民を避難させてください！","ENG":"It's dangerous! Please hurry and get the islanders to safety!","TWN":"危險！大家快帶島民撤離！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 어마어마하게 크잖아……!","JPN":"くそ、とんでもなくデカい……！","ENG":"Damn it, that thing's huge...!","TWN":"可惡，好大一隻……！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통! 출력 제한 풀어!","JPN":"おい、ポンコツ！　出力制限を解除しろ！","ENG":"Hey, tin can! Take off the output limiter!","TWN":"喂，鐵桶！解除輸出限制！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};